var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……도망쳤나.","JPN":"……逃げたか。","ENG":"…Escaped.","TWN":"……跑掉了嗎？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"시설의 상태는 아무일도 없었던 것 같군.","JPN":"施設の状態を見ると、何もなかったかのようだ。","ENG":"The building’s condition... No evidence of conflict.","TWN":"從現場的狀態看來，好像什麼事都沒發生過一樣。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"도망친 것이 아니라, 도망치게 해 준 것이라면…….","JPN":"逃げたのではなく、わざと逃がしたのなら……","ENG":"If she did not escape, but rather they let her escape...","TWN":"難道她不是自己跑掉，而是故意放她走的……"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"침입자에게 경고한다. 상부에서 보낸 카운터가 가는 중이다.","JPN":"侵入者に警告する。上層部から送られたカウンターがそっちへ向かっている。","ENG":"Warning to the intruder. Counters from the head office are on their way.","TWN":"警告入侵者，制裁者正在前往當中。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"수도를 헤집어 놓는 걸로도 모자라 보안국에 무력으로 침입하다니, 각오는 됐겠지.","JPN":"首都を修羅場にするだけでは飽き足らず、保安局に武力で侵入してくるとは、覚悟はできているのだろうな。","ENG":"It was not enough for you to tear up the capital, but now you are even forcefully trespassing the Department of National Security’s main office.","TWN":"把首都搞得一團糟還不夠，現在竟然還以武力闖進安全局，束手就擒吧！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"네놈은 우리의 조국을 모욕했다. 국민들이 지켜보는 가운데 심판해 주마.","JPN":"お前は祖国を侮辱した。国民が見守る中で裁いてくれる。","ENG":"You have insulted the motherland. You shall be judged in front of the people of this great land.","TWN":"竟敢藐視國家，你就在國民面前接受審判吧！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"너희의 법에는 따를 수 없다. 역병과 결탁한 이들과는 상종하지 않는 것이 마땅할지니.","JPN":"そなたらの法には従えん。疫病と結託した者とは交わらん方がいい。","ENG":"I shall not abide by your law. The laws of those who have colluded with the plague have no power over me.","TWN":"我無法遵守你們的法律，因為我不會和勾結瘟疫的人打交道。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"같잖은 연기 집어치워라. 네가 그래 봐야 결국 알량한 힘을 믿는 카운터겠지.","JPN":"くだらない演技はやめろ。結局はつまらない力に頼るカウンターだろう。","ENG":"Enough with this ridiculous performance. I suppose you’re nothing but an overconfident Counter.","TWN":"少在那邊胡言亂語，我看你也不過就是憑藉微薄力量的制裁者。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"우리는 어떤 희생을 감수해서라도 너를 처단할 거다.","JPN":"私たちはどんな犠牲を払ってでも、お前を処断する。","ENG":"We will punish you at all costs.","TWN":"無論要犧牲多少人，我們都會處決你的！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"네 뜻이 그러하다면 그대로 행하라.","JPN":"そなたの志がそうであれば思うままにせよ。","ENG":"If that is your will, then execute it.","TWN":"有本事就試試看吧。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"허나 제 아무리 고결한 뜻인들, 무지한 자들 뒤에 숨어 외치는 한 바람처럼 가벼울 따름이로다.","JPN":"だがいくら高潔な志であろうとも、無知な者たちの背後に隠れて叫ぶ限り、風のように軽いものでしかない。","ENG":"However, no matter how noble the goal, it is meaningless coming from the ignorant, who shouts his opinion in hiding. Such will is as weak and light as a gentle breeze.","TWN":"不過就算你講得再好聽，躲在眾人背後大放厥詞的人根本不足畏懼。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"……그래. 숨어서 외치면 소용없지.","JPN":"……そうね。隠れて叫んでちゃ意味がない。","ENG":"...Agreed. There is no point in shouting while hiding.","TWN":"……沒錯，躲在後面大放厥詞是沒用的。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L19_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"너는…….","JPN":"貴様は……","ENG":"You...","TWN":"你是……"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"마에스트로와 친분이 있던 여인이로군.","JPN":"マエストロと親交があった女だな。","ENG":"The woman acquainted with Maestra.","TWN":"和指揮家一起的女人。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"너에게는 용무가 없다. 어찌하여 내 앞을 가로막는 것인가.","JPN":"貴様には用がない。何故我の前に立ちふさがる。","ENG":"I have no business with you. Why do you stand in my way?","TWN":"我不是來找你的，你為何要攔住我的去路？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"간단해. 레아를 괴롭혔잖아.","JPN":"簡単よ。レアをいじめたでしょう。","ENG":"It’s simple. You messed with Leah.","TWN":"答案很簡單，因為你弄傷蕾亞。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"레아도 아주머니도, 둘 다 내가 돌봐 온 인간들이야. 힘들지만 보람 있는 나날이었어.","JPN":"レアもおばさんも、両方とも私が面倒を見てきた人間たちなの。大変だったけどやりがいのある毎日だった。","ENG":"Both Leah and Madam, are humans that I look after. It’s been difficult, but very fruitful and enjoyable.","TWN":"蕾亞和伯母都是我在照顧的人類，雖然每天都很累，卻累得很值得。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"그런데 예하께서 훼방을 놓는 바람에……. 더 즐길 수 없게 됐는걸.","JPN":"でも猊下に邪魔されて……もう楽しめなくなっちゃったわ。","ENG":"But then Eminence interrupted and... Well, I cannot enjoy it any longer.","TWN":"都是因為主教來攪局……害我無法再享受這樣的樂趣。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L28_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"방금, 예하라 하였나?","JPN":"今、猊下と言ったか？","ENG":"Eminence was the word you just uttered, was it not?","TWN":"你剛才，是叫我主教嗎？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"큭……!","JPN":"くっ……！","ENG":"Khhk...!","TWN":"唔……！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BASS_HARMONY_CHANGE_HIDE","text":{"KOREA":"우후후. 확실히 마왕님의 수법이라 정교하네. 예하의 코도 제 기능을 못 해.","JPN":"うふふ。確かに魔王様の手法だけに精巧だわ。猊下の鼻も騙せちゃうくらいに。","ENG":"Fuu fuu. It really is quite the exquisite trick of the Demon Lord. To fool even the nose of Eminence.","TWN":"呵呵呵，真不愧是出自魔王之手，毫無破綻呢！連主教都沒發現。"},"stage":{"bg":"FACILITY","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_CHANGE_HIDE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그 콘트라베이스……. 카르멘이로군.","JPN":"そのコントラバス……カルメンであるな。","ENG":"That contrabass... Carmen.","TWN":"那把低音提琴……原來你是卡門。"},"stage":{"bg":"FACILITY","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"본래의 네 용모는 그와 같지 않았을 터. 누구에게서 훔친 것이냐.","JPN":"本来の貴様の外見はそうでなかったはず。誰から盗んだものか。","ENG":"That is not your original appearance. That form, from whom did you steal it?","TWN":"這和你原本的容貌相去甚遠，你是從誰那裡偷來的？"},"stage":{"bg":"FACILITY","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"떽. 훔치다뇨. 체통에 어긋나지 않는 말씨를 쓰셔야죠, 예하.","JPN":"めっ。盗んだなんて。品位に合った言葉遣いをなさいませ、猊下。","ENG":"Aww. Stealing? You should be a little more dignified with your words, Eminence.","TWN":"嘖，什麼偷來的，主教這麼說話有失身分喔～"},"stage":{"bg":"FACILITY","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"이 몸은 주인을 잃었는걸. 나는 그걸 학회의 도움으로 거두어 줬을 뿐이야.","JPN":"この体は持ち主がいないんだもの。私はそれを学会のお手伝いで引き取ってあげただけ。","ENG":"This body has lost its original owner. With the help of the Society, I just took this body.","TWN":"是這副軀殼失去主人，而我只是在學會的幫助之下取得這副軀殼的。"},"stage":{"bg":"FACILITY","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"FACILITY","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"귀여운 중사님이 기대보다 더 활약해 준 덕분에 레아 곁으로 돌아가긴 어려워졌지만…….","JPN":"かわいい軍曹さんが期待以上の活躍をしてくれたおかげで、レアのそばに帰るのは難しくなったけど……","ENG":"It’s been quite difficult getting back to Leah’s side as that cute little Sergeant performed better than expected but...","TWN":"不過現在因為那位可愛中士超出期待的出色表現，我可能很難再回到蕾亞身邊……"},"stage":{"bg":"FACILITY","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"예하는 어때? 몸도 편찮아 보이는데 내가 돌봐 줄까?","JPN":"猊下はどう？　具合が悪そうだけど、私が面倒を見てあげようか？","ENG":"What about you, Eminence? That body looks quite sickly. Shall I take care of you?","TWN":"主教你還好嗎？我看你似乎身體欠安，需要我來照顧你嗎？"},"stage":{"bg":"FACILITY","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"마에스트로라면, 너를 혼자 내 앞에 세우지 않았겠지.","JPN":"マエストロなら、貴様一人を私の前へ立たせなかったはずだ。","ENG":"Maestra would not have put you in front of me alone.","TWN":"我認識的指揮家，是不會讓你獨自出現在我面前的。"},"stage":{"bg":"FACILITY","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"여기 너를 위해 예비된 단두대가 왔으니, 안식에 들도록 하라.","JPN":"ここに貴様のために準備された断頭台がある、安息に入れ。","ENG":"This guillotine has been reserved for you. You shall rest in peace.","TWN":"這是為你而準備的斷頭台，進入安息吧。"},"stage":{"bg":"FACILITY","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"아직도 그런 하품 나오는 소리나 하고 다니네, 예하.","JPN":"まだそんなつまんないこと言ってるのね、猊下。","ENG":"Huh. Even now you still drone on like that, Eminence.","TWN":"你還在說那種老掉牙的話喔，主教？"},"stage":{"bg":"FACILITY","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……셰나.","JPN":"……シェナ。","ENG":"…Shena.","TWN":"……世娜。"},"stage":{"bg":"FACILITY","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"어디 있다 온 거야, 셰나? 그렇게 제멋대로 굴다가 지휘자님께 혼나던 거 잊었어?","JPN":"どこへ行ってたの、シェナ？　そうやって我がまましててマエストロに怒られたの、忘れちゃった？","ENG":"Where have you been, Shena? Did you forget how the Chief Conductor scolded you for going off on your own?","TWN":"你怎麼會出現，世娜？你忘記上次指揮家才因為你擅自行動，而教訓過你嗎？"},"stage":{"bg":"FACILITY","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그런 잔소리는 네가 기르는 가축들에게나 실컷 하지 그래.","JPN":"そういう小言はあなたが飼ってる家畜にでも言うことね。","ENG":"Leave that nagging for your livestock.","TWN":"你要碎念的話，麻煩請找你的寵物們！"},"stage":{"bg":"FACILITY","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"너야말로 제대로 싸울 줄도 모르면서 예하와 독대하려 들었잖아?","JPN":"あなたこそちゃんと戦えないくせに、猊下と一人で向き合おうとしたでしょう？","ENG":"You don’t even know how to fight properly and yet you tried taking on Eminence by yourself.","TWN":"你根本就沒上過戰場，還想跟主教單打獨鬥？"},"stage":{"bg":"FACILITY","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"그렇지만……. 모처럼 의욕을 내고 있었는데 거슬리게 굴잖니.","JPN":"だって……せっかくやる気を出してたのに邪魔するんだもの。","ENG":"Aww… I got motivated after a long time, but she's being quite unpleasant.","TWN":"話是沒錯……但我難得有點幹勁，你幹嘛出來礙事啦！"},"stage":{"bg":"FACILITY","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……셰나. 카르멘이 학회에 대해 언급하였다.","JPN":"……シェナ。カルメンが学会を口にしていた。","ENG":"...Shena. Carmen mentioned the Society.","TWN":"……世娜，卡門剛才有提到學會，"},"stage":{"bg":"FACILITY","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"너희가 그들과 손잡았다면, 몽타뉴는 처음부터 이용당한 것인가?","JPN":"貴様らが彼らと手を組んだなら、モンターニュは最初から利用されていたのか？","ENG":"If you’ve joined them... Was Montagne being used from the beginning?","TWN":"意思是你們原本就有和學會合作，蒙塔妮從一開始就是被利用的嗎？"},"stage":{"bg":"FACILITY","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"흐흥, 그렇다고 해 둘까.","JPN":"ふふん、そいうことにしておこうかな。","ENG":"Mhm, I guess you could say so.","TWN":"呵呵，是這麼說嗎？"},"stage":{"bg":"FACILITY","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"제프티 바이오테크가 통째로 날아가는 바람에 자질구레한 일을 해 줄 일손이 부족해졌거든.","JPN":"ジェフティ・バイオテックが丸ごとふっ飛んだせいで、細かい仕事のための人手が足りなくなったの。","ENG":"After Jehuty Biotech was lost entirely, we were a little short on hands to do all the little dirty work.","TWN":"因為傑夫堤生物科技出事後，很多雞毛蒜皮的小事就沒人可以做的嘛～"},"stage":{"bg":"FACILITY","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"골골거리기 전에도 약했던 주제에 최고 지휘자님을 깨워서 뭘 하고 싶었는지 모르겠지만?","JPN":"ひ弱になる前にも弱かったくせに、マエストロを覚醒させて何がしたかったのかわからないけどね？","ENG":"She suffered from such weak health way before, I’m not exactly sure what her plan was after waking up the Chief Conductor, but...","TWN":"明明就很弱，我也不知道她喚醒首席指揮家是想做什麼？"},"stage":{"bg":"FACILITY","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"응. 적어도 예하를 끌어들이지 않았으면 참 좋았을 텐데.","JPN":"うん。少なくとも猊下を引き込まなければよかったのにね。","ENG":"Yes. At the very least, it would have been nice if she didn’t drag Eminence into this.","TWN":"嗯，至少不應該把主教扯進來的。"},"stage":{"bg":"FACILITY","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"레아는 요즘 들어 보살펴 줄 기회가 줄어들었거든. 적당히 괴롭히기만 했어도 예쁘게 봐 줬을 거야.","JPN":"最近レアのお世話をするチャンスがなかったでしょう。適当にいじめるくらいなら大目に見てあげたのに。","ENG":"I’ve had fewer opportunities to take care of Leah these days. I would’ve let it slide if only she wasn’t beset too much.","TWN":"我最近比較沒機會可以照顧蕾亞，若你適可而止的話，我還可以睜一隻眼閉一隻眼。"},"stage":{"bg":"FACILITY","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그래서 말인데, 예하도 너무 설쳤어. 적어도 보안국까지 기어들어 오진 말았어야지.","JPN":"それでだけど、猊下も出しゃばりすぎ。少なくとも保安局までは来ちゃいけなかった。","ENG":"Speaking of which... Eminence has been so unruly. You shouldn’t have crawled into the National Security.","TWN":"但主教你做得太過火啦，起碼不該闖到安全局來的嘛～"},"stage":{"bg":"FACILITY","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"즉흥곡을 들려 주는 건 오랜만이네. 준비됐어?","JPN":"即興曲を披露するのは久しぶりね。準備はいい？","ENG":"It’s been quite a long time since I’ve played an improvisational piece. Are you ready?","TWN":"好久即興發揮囉，準備好沒？"},"stage":{"bg":"FACILITY","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"FACILITY","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"와라. 셰나.\xA0","JPN":"参れ。シェナ。\xA0","ENG":"Come, Shena.","TWN":"來吧，世娜。\xA0"},"stage":{"bg":"FACILITY","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};